def power(base, exp, mod):
    res = 1
    base %= mod
    while exp > 0:
        if exp % 2 == 1:
            res = (res * base) % mod
        base = (base * base) % mod
        exp //= 2
    return res

def mod_inverse(n, mod):
    return power(n, mod - 2, mod)

def ntt(a, p, w):
    N = len(a)
    if not (N > 0 and (N & (N - 1) == 0)):
        raise ValueError("Length of array must be a power of 2.")

    j = 0
    for i in range(N):
        if i < j:
            a[i], a[j] = a[j], a[i]
        k = N // 2
        while j >= k:
            j -= k
            k //= 2
        j += k

    len_block = 2
    while len_block <= N:
        w_m = power(w, N // len_block, p)
        for k in range(0, N, len_block):
            w_cur = 1
            for j in range(len_block // 2):
                u = a[k + j]
                v = (a[k + j + len_block // 2] * w_cur) % p
                a[k + j] = (u + v) % p
                a[k + j + len_block // 2] = (u - v + p) % p
                w_cur = (w_cur * w_m) % p
        len_block *= 2
    return a

def intt(A, p, inv_w):
    N = len(A)
    if not (N > 0 and (N & (N - 1) == 0)):
        raise ValueError("Length of array must be a power of 2.")

    transformed_A = ntt(A, p, inv_w)

    N_inv = mod_inverse(N, p)
    for i in range(N):
        transformed_A[i] = (transformed_A[i] * N_inv) % p
    return transformed_A
